import UIKit
import CryptoKit

class BankingApp {
    private var accountBalance: Double
    private let encryptionKey: SymmetricKey
    
    init(initialBalance: Double) {
        self.accountBalance = initialBalance
        self.encryptionKey = SymmetricKey(size: .bits256)
    }
    
    func getAccountBalance() -> Double {
        return accountBalance
    }
    
    func processTransaction(amount: Double, isDeposit: Bool) -> Bool {
        let encryptedAmount = encryptTransactionAmount(amount)
        
        if isDeposit {
            accountBalance += decryptedTransactionAmount(encryptedAmount)
        } else {
            if accountBalance >= amount {
                accountBalance -= decryptedTransactionAmount(encryptedAmount)
            } else {
                return false
            }
        }
        return true
    }
    
    private func encryptTransactionAmount(_ amount: Double) -> Data {
        let amountData = String(amount).data(using: .utf8)!
        let sealedBox = try! AES.GCM.seal(amountData, using: encryptionKey)
        return sealedBox.combined!
    }
    
    private func decryptedTransactionAmount(_ encryptedData: Data) -> Double {
        let sealedBox = try! AES.GCM.SealedBox(combined: encryptedData)
        let decryptedData = try! AES.GCM.open(sealedBox, using: encryptionKey)
        let amountString = String(data: decryptedData, encoding: .utf8)!
        return Double(amountString) ?? 0.0
    }
}

class ViewController: UIViewController {
    let bankingApp = BankingApp(initialBalance: 1000.0)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        displayBalance()
    }
    
    func displayBalance() {
        let balance = bankingApp.getAccountBalance()
        print("Current Balance: \(balance)")
    }
    
    func deposit(amount: Double) {
        if bankingApp.processTransaction(amount: amount, isDeposit: true) {
            print("Deposit successful!")
        } else {
            print("Deposit failed!")
        }
        displayBalance()
    }
    
    func withdraw(amount: Double) {
        if bankingApp.processTransaction(amount: amount, isDeposit: false) {
            print("Withdrawal successful!")
        } else {
            print("Insufficient funds!")
        }
        displayBalance()
    }
}